#pragma once
#include <string>
#include <vector>
#include <map>
#include <simLib/simConst.h>
#include <QVariantMap>
#include <QJsonObject>
#include <QJsonDocument>
#include <magic_enum/magic_enum.hpp>

struct PropertyInfo {
    QVariantMap map;
    std::string json;
    PropertyInfo(std::initializer_list<QPair<QString, QVariant>> init)
    {
        for(const auto& [k, v] : init)
            map.insert(k, v);
        json = QJsonDocument(QJsonObject::fromVariantMap(map)).toJson(QJsonDocument::Compact).toStdString();
    }
};

struct SProperty {
    const char* name;
    int type;
    int flags;
    const PropertyInfo info;
    int oldEnums[5];
};

template<typename T>
std::map<int, std::string> buildEnumToStringMap()
{
    std::map<int, std::string> enum_to_string;
    for (auto [enum_val, name_view] : magic_enum::enum_entries<T>())
        enum_to_string.emplace(static_cast<int>(enum_val), std::string(name_view));
    return enum_to_string;
}

